  // Đánh giá nhanh theo tỉ lệ đúng
  const ratio = total > 0 ? score / total : 0;
  const verdict =
    ratio >= 0.8
      ? { icon: 'trophy', text: 'Xuất sắc!', color: colors.primary }
      : ratio >= 0.5
