        showsVerticalScrollIndicator={false}
      >
        {/* Thẻ điểm */}
        <Card highlighted style={styles.scoreCard}>
          <Ionicons
            name={verdict.icon as keyof typeof Ionicons.glyphMap}
            size={56}
            color={verdict.color}
          />
